const crypto = require('crypto');
const sig = $node['Webhook: Product Update'].json.headers['x-printhub-signature'];
const hmac = crypto.createHmac('sha256', process.env.N8N_WEBHOOK_SECRET).update(JSON.stringify($node['Webhook: Product Update'].json.body)).digest('hex');
if (sig !== hmac) throw new Error('Invalid signature');
return $node['Webhook: Product Update'].json.body;

const { changes, oldValues, newValues } = $json;
const oldPrice = parseFloat(oldValues?.basePrice || 0);
const newPrice = parseFloat(newValues?.basePrice || 0);
const priceDiff = oldPrice > 0 ? Math.abs((newPrice - oldPrice) / oldPrice) * 100 : 0;
const isPriceChange = priceDiff >= 5;
const isStockChange = changes?.includes('stock') || changes?.includes('availability');
const isGoingOutOfStock = isStockChange && (newValues?.stock === 0 || newValues?.availability === 'OUT_OF_STOCK');
return [{ ...$json, priceDiff: priceDiff.toFixed(1), isPriceChange, isStockChange, isGoingOutOfStock, priceDirection: newPrice > oldPrice ? 'increase' : 'decrease' }];

const crypto = require('crypto');
const sig = $node['Webhook: Sync All'].json.headers['x-printhub-signature'];
const hmac = crypto.createHmac('sha256', process.env.N8N_WEBHOOK_SECRET).update(JSON.stringify($node['Webhook: Sync All'].json.body)).digest('hex');
if (sig !== hmac) throw new Error('Invalid signature');
return $node['Webhook: Sync All'].json.body;

const products = $json.products || [];
const metaBatch = products.map(p => ({
  retailer_id: p.id,
  name: p.name,
  description: p.shortDescription || p.name,
  availability: p.availability === 'IN_STOCK' ? 'in stock' : 'out of stock',
  condition: 'new',
  price: `${Math.round(p.basePriceKes * 100)} KES`,
  link: `https://printhub.africa/shop/${p.slug}`,
  brand: 'PrintHub Africa',
  google_product_category: 'Arts & Entertainment > Hobbies & Creative Arts'
}));
return [{ products, metaBatch, count: products.length }];

