const jwt = require('jsonwebtoken');
const header = { alg: 'ES256', kid: process.env.APPLE_KEY_ID };
const payload = { iss: process.env.APPLE_TEAM_ID, iat: Math.floor(Date.now()/1000), exp: Math.floor(Date.now()/1000)+1800, origin: 'https://printhub.africa' };
const privateKey = Buffer.from(process.env.APPLE_PRIVATE_KEY, 'base64').toString();
return [{ token: jwt.sign(payload, privateKey, { header }) }];

